    external fun uniffi_ciris_edge_checksum_func_crate_version(
    ): Short
    external fun uniffi_ciris_edge_checksum_func_current_ratchet_id(
    ): Short
    external fun uniffi_ciris_edge_checksum_func_identity_hash(
    ): Short
    external fun uniffi_ciris_edge_checksum_func_identity_pubkeys(
    ): Short
    external fun uniffi_ciris_edge_checksum_func_last_rotation_at(
    ): Short
    external fun uniffi_ciris_edge_checksum_func_link_count(
