sealed class EdgeBindingsException(message: String): kotlin.Exception(message) {
        
        class NotInitialized(message: String) : EdgeBindingsException(message)
        
        class NotImplemented(message: String) : EdgeBindingsException(message)
        
        class NotFound(message: String) : EdgeBindingsException(message)
        
        class InvalidArgument(message: String) : EdgeBindingsException(message)
        
        class Internal(message: String) : EdgeBindingsException(message)
        
        class Unsupported(message: String) : EdgeBindingsException(message)
        
        class Persist(message: String) : EdgeBindingsException(message)
        
        class Transport(message: String) : EdgeBindingsException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<EdgeBindingsException> {
        override fun lift(error_buf: RustBuffer.ByValue): EdgeBindingsException = FfiConverterTypeEdgeBindingsError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeEdgeBindingsError : FfiConverterRustBuffer<EdgeBindingsException> {
    override fun read(buf: ByteBuffer): EdgeBindingsException {
        
            return when(buf.getInt()) {
            1 -> EdgeBindingsException.NotInitialized(FfiConverterString.read(buf))
            2 -> EdgeBindingsException.NotImplemented(FfiConverterString.read(buf))
            3 -> EdgeBindingsException.NotFound(FfiConverterString.read(buf))
            4 -> EdgeBindingsException.InvalidArgument(FfiConverterString.read(buf))
            5 -> EdgeBindingsException.Internal(FfiConverterString.read(buf))
            6 -> EdgeBindingsException.Unsupported(FfiConverterString.read(buf))
            7 -> EdgeBindingsException.Persist(FfiConverterString.read(buf))
            8 -> EdgeBindingsException.Transport(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: EdgeBindingsException): ULong {
        return 4UL
    }

    override fun write(value: EdgeBindingsException, buf: ByteBuffer) {
        when(value) {
            is EdgeBindingsException.NotInitialized -> {
                buf.putInt(1)
                Unit
            }
            is EdgeBindingsException.NotImplemented -> {
                buf.putInt(2)
                Unit
            }
            is EdgeBindingsException.NotFound -> {
                buf.putInt(3)
                Unit
            }
            is EdgeBindingsException.InvalidArgument -> {
                buf.putInt(4)
                Unit
            }
            is EdgeBindingsException.Internal -> {
                buf.putInt(5)
                Unit
            }
            is EdgeBindingsException.Unsupported -> {
                buf.putInt(6)
                Unit
            }
            is EdgeBindingsException.Persist -> {
                buf.putInt(7)
                Unit
            }
            is EdgeBindingsException.Transport -> {
                buf.putInt(8)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




